compositionExample.codeTrait:
use Academorix\AccessRequest\Concerns\IsAccessRequestable;

final class Invoice extends Model
{
    use IsAccessRequestable;

    public static function accessRequestResourceType(): string
    {
        return 'invoice';
    }

    public static function accessRequestPermissions(): array
    {
        return ['invoices.view', 'invoices.update', 'invoices.export'];
    }
}

