Schema::create('invoices', function (Blueprint $t) {
    $t->string('id', 64)->primary();
    $t->tenantable();
    $t->access_requestable();   // register-only; no column added
    $t->decimal('amount', 12, 2);
    $t->string('currency', 3);
    $t->timestamps();
});
